@Service
public class UserService {
    private final UserRepository repository;

    // Constructor Injection (Highly recommended over @Autowired on fields)
    // Spring automatically injects the UserRepository bean here when creating UserService.
    public UserService(UserRepository repository) {
        this.repository = repository;
    }
}

@RestController // Combines @Controller and @ResponseBody (returns JSON instead of HTML views)
@RequestMapping("/api/users")
public class UserController {

    private final UserService userService; // Injected @Service bean

    public UserController(UserService userService) {
        this.userService = userService;
    }
}

@PostMapping
public ResponseEntity<User> createUser(@RequestBody User user) {
    // @RequestBody deserializes incoming JSON into the User Java object
    User savedUser = userService.save(user);
    // Return the created object along with an HTTP 201 Created status code
    return new ResponseEntity<>(savedUser, HttpStatus.CREATED);
}

