@Bean
public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
    http.csrf().disable() // Typically disabled for stateless REST APIs
        .authorizeHttpRequests()
        .requestMatchers("/api/auth/**").permitAll() // Public endpoints
        .requestMatchers("/api/admin/**").hasRole("ADMIN") // Role-based access
        .anyRequest().authenticated() // All others require authentication
        .and()
        .sessionManagement().sessionCreationPolicy(SessionCreationPolicy.STATELESS);
    // Custom JWT filter would be added here
    return http.build();
}

@Aspect
@Component
public class PerformanceLoggingAspect {

    // Pointcut: Matches any method execution inside the 'service' package
    @Around("execution(* com.myapp.service.*.*(..))")
    public Object logExecutionTime(ProceedingJoinPoint joinPoint) throws Throwable {
        long start = System.currentTimeMillis();
        Object proceed = joinPoint.proceed(); // Allows the actual target method to run
        long executionTime = System.currentTimeMillis() - start;
        System.out.println(joinPoint.getSignature() + " took " + executionTime + "ms");
        return proceed;
    }
}

