@Bean
public Step processInterestStep(ItemReader<Account> reader, 
                                ItemProcessor<Account, Account> processor, 
                                ItemWriter<Account> writer) {
    return stepBuilderFactory.get("processInterestStep")
        .<Account, Account>chunk(1000) // Process in chunks of 1000
        .reader(reader)
        .processor(processor)
        .writer(writer)
        .faultTolerant()
        .skipLimit(10) // Skip up to 10 corrupt records without failing the job
        .skip(DataIntegrityViolationException.class)
        .build();
}

